141: func (l *loader) bpfMasqAddrs(ifName string) (masq4, masq6 netip.Addr) {
142: 	if l.cfg.DeriveMasqIPAddrFromDevice != "" {
143: 		ifName = l.cfg.DeriveMasqIPAddrFromDevice
144: 	}
145: 
146: 	addrs := l.getNodeConfig().NodeAddresses
147: 
148: 	find := func(devName string) bool {
149: 		for _, addr := range addrs {
150: 			if addr.DeviceName != devName {
151: 				continue
152: 			}
153: 			if !addr.Primary {
154: 				continue
155: 			}
156: 			if addr.Addr.Is4() && !masq4.IsValid() {
157: 				masq4 = addr.Addr
158: 			} else if addr.Addr.Is6() && !masq6.IsValid() {
159: 				masq6 = addr.Addr
160: 			}
161: 			done := (!option.Config.EnableIPv4Masquerade || masq4.IsValid()) &&
162: 				(!option.Config.EnableIPv6Masquerade || masq6.IsValid())
163: 			if done {
164: 				return true
165: 			}
166: 		}
167: 		return false
168: 	}
169: 
170: 	// Try to find suitable masquerade address first from the given interface.
171: 	if !find(ifName) {
172: 		// No suitable masquerade addresses were found for this device. Try the fallback
173: 		// addresses.
174: 		find(tables.WildcardDeviceName)
175: 	}
176: 
177: 	return
178: }
