180: // patchHostNetdevDatapath calculates the changes necessary
181: // to attach the host endpoint datapath to different interfaces.
182: func (l *loader) patchHostNetdevDatapath(ep datapath.Endpoint, ifName string) (map[string]uint64, map[string]string, error) {
183: 	opts := ELFVariableSubstitutions(ep)
184: 	strings := ELFMapSubstitutions(ep)
185: 
186: 	iface, err := safenetlink.LinkByName(ifName)
187: 	if err != nil {
188: 		return nil, nil, err
189: 	}
190: 
191: 	// The THIS_INTERFACE_MAC value is specific to each attachment interface.
192: 	mac := mac.MAC(iface.Attrs().HardwareAddr)
193: 	if mac == nil {
194: 		// L2-less device
195: 		mac = make([]byte, 6)
196: 		opts["ETH_HLEN"] = uint64(0)
197: 	}
198: 	opts["THIS_INTERFACE_MAC_1"] = uint64(sliceToBe32(mac[0:4]))
199: 	opts["THIS_INTERFACE_MAC_2"] = uint64(sliceToBe16(mac[4:6]))
200: 
201: 	ifIndex := uint32(iface.Attrs().Index)
202: 
203: 	if !option.Config.EnableHostLegacyRouting {
204: 		opts["SECCTX_FROM_IPCACHE"] = uint64(secctxFromIpcacheEnabled)
205: 	} else {
206: 		opts["SECCTX_FROM_IPCACHE"] = uint64(secctxFromIpcacheDisabled)
207: 	}
208: 
209: 	opts["NATIVE_DEV_IFINDEX"] = uint64(ifIndex)
210: 
211: 	if option.Config.EnableBPFMasquerade && ifName != defaults.SecondHostDevice {
212: 		ipv4, ipv6 := l.bpfMasqAddrs(ifName)
213: 
214: 		if option.Config.EnableIPv4Masquerade && ipv4.IsValid() {
215: 			opts["IPV4_MASQUERADE"] = uint64(byteorder.NetIPv4ToHost32(ipv4.AsSlice()))
216: 		}
217: 		if option.Config.EnableIPv6Masquerade && ipv6.IsValid() {
218: 			ipv6Bytes := ipv6.AsSlice()
219: 			opts["IPV6_MASQUERADE_1"] = sliceToBe64(ipv6Bytes[0:8])
220: 			opts["IPV6_MASQUERADE_2"] = sliceToBe64(ipv6Bytes[8:16])
221: 		}
222: 	}
223: 
224: 	callsMapHostDevice := bpf.LocalMapName(callsmap.HostMapName, templateLxcID)
225: 	strings[callsMapHostDevice] = bpf.LocalMapName(callsmap.NetdevMapName, uint16(ifIndex))
226: 
227: 	return opts, strings, nil
228: }
