602: // ReloadDatapath reloads the BPF datapath programs for the specified endpoint.
603: //
604: // It attempts to find a pre-compiled
605: // template datapath object to use, to avoid a costly compile operation.
606: // Only if there is no existing template that has the same configuration
607: // parameters as the specified endpoint, this function will compile a new
608: // template for this configuration.
609: //
610: // This function will block if the cache does not contain an entry for the
611: // same EndpointConfiguration and multiple goroutines attempt to concurrently
612: // CompileOrLoad with the same configuration parameters. When the first
613: // goroutine completes compilation of the template, all other CompileOrLoad
614: // invocations will be released.
615: func (l *loader) ReloadDatapath(ctx context.Context, ep datapath.Endpoint, stats *metrics.SpanStat) (hash string, err error) {
616: 	dirs := directoryInfo{
617: 		Library: option.Config.BpfDir,
618: 		Runtime: option.Config.StateDir,
619: 		State:   ep.StateDir(),
620: 		Output:  ep.StateDir(),
621: 	}
622: 
623: 	cfg := l.getNodeConfig()
624: 
625: 	spec, hash, err := l.templateCache.fetchOrCompile(ctx, cfg, ep, &dirs, stats)
626: 	if err != nil {
627: 		return "", err
628: 	}
629: 
630: 	stats.BpfLoadProg.Start()
631: 	err = l.reloadDatapath(ep, spec)
632: 	stats.BpfLoadProg.End(err == nil)
633: 	return hash, err
634: }
